import React, { useState } from 'react';

export default function AdminDashboard() {
  const [activeTab, setActiveTab] = useState('overview');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');

  const stats = [
    { label: 'Total Complaints', value: '145', icon: '📋', color: 'from-blue-400 to-blue-600', trend: '+12%' },
    { label: 'Pending', value: '23', icon: '⏳', color: 'from-yellow-400 to-yellow-600', trend: '-5%' },
    { label: 'Resolved', value: '112', icon: '✅', color: 'from-emerald-400 to-emerald-600', trend: '+8%' },
    { label: 'Avg Response', value: '2.4h', icon: '⚡', color: 'from-purple-400 to-purple-600', trend: '-20%' },
  ];

  const recentComplaints = [
    { id: 'CMT-001', title: 'Wi-Fi not working in Hostel A', category: 'IT / Wi-Fi', status: 'open', priority: 'high', date: '2024-04-08', assignedTo: 'John Doe' },
    { id: 'CMT-002', title: 'Canteen food quality issue', category: 'Canteen / Food', status: 'in_progress', priority: 'medium', date: '2024-04-07', assignedTo: 'Jane Smith' },
    { id: 'CMT-003', title: 'Room maintenance required', category: 'Hostel & Accommodation', status: 'resolved', priority: 'low', date: '2024-04-06', assignedTo: 'Mike Johnson' },
    { id: 'CMT-004', title: 'Broken AC in Library', category: 'Infrastructure', status: 'open', priority: 'high', date: '2024-04-05', assignedTo: 'Unassigned' },
  ];

  const getStatusColor = (status) => {
    const colors = {
      open: { bg: 'bg-blue-100', text: 'text-blue-700', label: 'Open' },
      in_progress: { bg: 'bg-yellow-100', text: 'text-yellow-700', label: 'In Progress' },
      resolved: { bg: 'bg-emerald-100', text: 'text-emerald-700', label: 'Resolved' },
      closed: { bg: 'bg-slate-100', text: 'text-slate-700', label: 'Closed' },
    };
    return colors[status] || colors.open;
  };

  const getPriorityColor = (priority) => {
    const colors = {
      low: 'bg-slate-100 text-slate-700',
      medium: 'bg-yellow-100 text-yellow-700',
      high: 'bg-orange-100 text-orange-700',
      critical: 'bg-red-100 text-red-700',
    };
    return colors[priority] || colors.medium;
  };

  const filteredComplaints = recentComplaints.filter((complaint) => {
    const matchesSearch = complaint.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         complaint.id.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = filterStatus === 'all' || complaint.status === filterStatus;
    return matchesSearch && matchesStatus;
  });

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="glass-card p-8 space-y-2">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-4xl font-bold text-slate-900">👨‍💼 Admin Dashboard</h1>
            <p className="text-slate-600 mt-2">Manage complaints and monitor system performance</p>
          </div>
          <span className="text-4xl">📊</span>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, idx) => (
          <div key={idx} className={`glass-card p-6 space-y-3 bg-gradient-to-br ${stat.color} hover:shadow-lg transition-all`}>
            <div className="flex items-start justify-between">
              <div className="text-4xl">{stat.icon}</div>
              <span className="text-xs font-semibold text-white/70 px-2 py-1 bg-white/20 rounded-full">{stat.trend}</span>
            </div>
            <div>
              <p className="text-sm text-white/80 font-medium">{stat.label}</p>
              <p className="text-3xl font-bold text-white">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div className="glass-card p-6 flex gap-2 flex-wrap">
        {[
          { id: 'overview', label: '📊 Overview' },
          { id: 'complaints', label: '📋 All Complaints' },
          { id: 'users', label: '👥 Users' },
          { id: 'analytics', label: '📈 Analytics' },
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`px-6 py-3 rounded-lg font-semibold transition-all ${
              activeTab === tab.id
                ? 'bg-gradient-to-r from-blue-600 to-blue-500 text-white shadow-lg'
                : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Content based on tab */}
      {activeTab === 'overview' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Recent Complaints */}
          <div className="lg:col-span-2 glass-card p-8 space-y-6">
            <div className="flex items-center justify-between">
              <h2 className="text-2xl font-bold text-slate-900">Recent Complaints</h2>
              <button className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-semibold hover:bg-blue-700 transition-all">
                View All
              </button>
            </div>

            <div className="space-y-3">
              {recentComplaints.slice(0, 3).map((complaint) => {
                const statusColor = getStatusColor(complaint.status);
                return (
                  <div key={complaint.id} className="p-4 bg-gradient-to-r from-slate-50 to-slate-100 rounded-lg border border-slate-200 hover:shadow-md transition-all">
                    <div className="flex items-start justify-between mb-2">
                      <div className="flex-1">
                        <p className="font-mono text-xs text-blue-600 font-semibold">{complaint.id}</p>
                        <p className="font-semibold text-slate-900 mt-1">{complaint.title}</p>
                      </div>
                      <span className={`px-3 py-1 rounded-full text-xs font-semibold whitespace-nowrap ml-2 ${statusColor.bg} ${statusColor.text}`}>
                        {statusColor.label}
                      </span>
                    </div>
                    <div className="flex gap-4 text-sm text-slate-600">
                      <span>📂 {complaint.category}</span>
                      <span className={`px-2 py-0.5 rounded ${getPriorityColor(complaint.priority)} text-xs font-semibold`}>{complaint.priority.toUpperCase()}</span>
                      <span>👤 {complaint.assignedTo}</span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Quick Actions */}
          <div className="glass-card p-8 space-y-6">
            <h2 className="text-2xl font-bold text-slate-900">Quick Actions</h2>
            <div className="space-y-3">
              <button className="w-full px-4 py-3 bg-gradient-to-r from-blue-600 to-blue-500 text-white rounded-lg font-semibold hover:shadow-lg hover:scale-105 transition-all">
                📝 Review Pending
              </button>
              <button className="w-full px-4 py-3 bg-gradient-to-r from-emerald-600 to-emerald-500 text-white rounded-lg font-semibold hover:shadow-lg hover:scale-105 transition-all">
                ✅ Approve Answers
              </button>
              <button className="w-full px-4 py-3 bg-gradient-to-r from-purple-600 to-purple-500 text-white rounded-lg font-semibold hover:shadow-lg hover:scale-105 transition-all">
                📊 View Reports
              </button>
              <button className="w-full px-4 py-3 bg-gradient-to-r from-orange-600 to-orange-500 text-white rounded-lg font-semibold hover:shadow-lg hover:scale-105 transition-all">
                👥 Export Data
              </button>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'complaints' && (
        <div className="glass-card p-8 space-y-6">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1">
              <input
                type="text"
                placeholder="Search by complaint ID or title..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>
            <select
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
              className="px-4 py-3 rounded-lg border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="all">All Status</option>
              <option value="open">Open</option>
              <option value="in_progress">In Progress</option>
              <option value="resolved">Resolved</option>
              <option value="closed">Closed</option>
            </select>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b-2 border-slate-300 bg-slate-100">
                  <th className="text-left py-3 px-4 font-semibold text-slate-700">ID</th>
                  <th className="text-left py-3 px-4 font-semibold text-slate-700">Title</th>
                  <th className="text-left py-3 px-4 font-semibold text-slate-700">Category</th>
                  <th className="text-center py-3 px-4 font-semibold text-slate-700">Priority</th>
                  <th className="text-center py-3 px-4 font-semibold text-slate-700">Status</th>
                  <th className="text-left py-3 px-4 font-semibold text-slate-700">Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredComplaints.map((complaint) => {
                  const statusColor = getStatusColor(complaint.status);
                  return (
                    <tr key={complaint.id} className="border-b border-slate-200 hover:bg-slate-50 transition-colors">
                      <td className="py-3 px-4 font-mono text-sm text-blue-600">{complaint.id}</td>
                      <td className="py-3 px-4 text-slate-900 font-medium">{complaint.title}</td>
                      <td className="py-3 px-4 text-slate-700">{complaint.category}</td>
                      <td className="py-3 px-4 text-center">
                        <span className={`px-3 py-1 rounded-full text-xs font-semibold ${getPriorityColor(complaint.priority)}`}>
                          {complaint.priority}
                        </span>
                      </td>
                      <td className="py-3 px-4 text-center">
                        <span className={`px-3 py-1 rounded-full text-xs font-semibold ${statusColor.bg} ${statusColor.text}`}>
                          {statusColor.label}
                        </span>
                      </td>
                      <td className="py-3 px-4">
                        <button className="text-blue-600 hover:text-blue-700 font-semibold text-sm">View</button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          {filteredComplaints.length === 0 && (
            <div className="text-center py-8">
              <p className="text-slate-600 text-lg">No complaints found</p>
            </div>
          )}
        </div>
      )}

      {activeTab === 'users' && (
        <div className="glass-card p-8">
          <h2 className="text-2xl font-bold text-slate-900 mb-6">User Management</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {[
              { role: 'Admins', count: '5', icon: '👨‍💼' },
              { role: 'Staff', count: '12', icon: '👨‍💻' },
              { role: 'Students', count: '2,340', icon: '👨‍🎓' },
            ].map((user, idx) => (
              <div key={idx} className="p-6 bg-gradient-to-br from-slate-50 to-slate-100 rounded-lg border border-slate-200 text-center">
                <p className="text-4xl mb-2">{user.icon}</p>
                <p className="text-3xl font-bold text-slate-900">{user.count}</p>
                <p className="text-slate-600 mt-2">{user.role}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'analytics' && (
        <div className="glass-card p-8">
          <h2 className="text-2xl font-bold text-slate-900 mb-6">Analytics Dashboard</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="p-6 bg-gradient-to-br from-slate-50 to-slate-100 rounded-lg border border-slate-200">
              <h3 className="font-semibold text-slate-900 mb-4">Complaints by Category</h3>
              <div className="space-y-3">
                {['Hostel', 'Academic', 'Canteen', 'Transport', 'IT'].map((cat, idx) => (
                  <div key={idx} className="flex items-center justify-between">
                    <span className="text-slate-700">{cat}</span>
                    <div className="flex-1 mx-4 h-2 bg-slate-200 rounded-full">
                      <div className="h-full bg-blue-500 rounded-full" style={{ width: `${Math.random() * 100}%` }}></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="p-6 bg-gradient-to-br from-slate-50 to-slate-100 rounded-lg border border-slate-200">
              <h3 className="font-semibold text-slate-900 mb-4">Status Distribution</h3>
              <div className="space-y-3">
                {['Open', 'In Progress', 'Resolved', 'Closed'].map((status, idx) => (
                  <div key={idx} className="flex items-center justify-between">
                    <span className="text-slate-700">{status}</span>
                    <span className="font-bold text-slate-900">{Math.floor(Math.random() * 50) + 10}%</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
